// // This module implements a 4-bit down-counter circuit that decrements its value on each rising edge of the clock signal 'clk'. The counter should also have an active-high reset 'rst' to reset the count to 0.
module up_counter_4bit(
	input clk,
	input rst_n,
	output reg [3:0] count
);

	always @(posedge clk or negedge rst_n) begin
		if (!rst_n) begin
			count <= 4'b0000;
		end
		else begin
			count <= count + 1'b1;
		end
	end

endmodule
